@app.before_request
def before_request_metrics():
    g.start_time = time.time()
    endpoint = request.endpoint or "unknown"
    method = request.method
    REQUEST_IN_PROGRESS.labels(method=method, endpoint=endpoint).inc()
    content_length = request.content_length or 0
    REQUEST_SIZE.labels(method=method, endpoint=endpoint).observe(content_length)


@app.after_request
def after_request_metrics(response):
    endpoint = request.endpoint or "unknown"
    method = request.method

    # Skip the /metrics endpoint itself to avoid self-referential noise
    if endpoint == "metrics":
        return response

    latency = time.time() - g.get("start_time", time.time())
    status = response.status_code

    REQUEST_COUNT.labels(method=method, endpoint=endpoint, http_status=status).inc()
    REQUEST_LATENCY.labels(method=method, endpoint=endpoint).observe(latency)
    REQUEST_LATENCY_SUMMARY.labels(method=method, endpoint=endpoint).observe(latency)
    REQUEST_IN_PROGRESS.labels(method=method, endpoint=endpoint).dec()

    response_size = response.content_length or 0
    RESPONSE_SIZE.labels(method=method, endpoint=endpoint).observe(response_size)

    if status >= 400:
        error_type = "client_error" if status < 500 else "server_error"
        ERROR_COUNT.labels(method=method, endpoint=endpoint, error_type=error_type).inc()

    return response


