def track_db_query(query_type: str, table: str):
    """Decorator to track database query duration."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            start = time.time()
            result = func(*args, **kwargs)
            duration = time.time() - start
            DB_QUERY_DURATION.labels(query_type=query_type, table=table).observe(duration)
            return result
        return wrapper
    return decorator


def track_external_call(service: str):
    """Decorator to track external API call duration and status."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            start = time.time()
            try:
                result = func(*args, **kwargs)
                duration = time.time() - start
                EXTERNAL_API_LATENCY.labels(service=service).observe(duration)
                EXTERNAL_API_CALLS.labels(service=service, status="success").inc()
                return result
            except Exception as e:
                duration = time.time() - start
                EXTERNAL_API_LATENCY.labels(service=service).observe(duration)
                EXTERNAL_API_CALLS.labels(service=service, status="error").inc()
                raise
        return wrapper
    return decorator


